mapper.select:
SELECT a.exam_cd, a.exam_nm, a.ISUSE, b.SBJ_CD, b.ITEM_NO, b.PASS_ANS, c.SBJ_NM FROM exam_mst a LEFT OUTER JOIN exam_pass_mst b on a.EXAM_CD = b.exam_cd LEFT OUTER JOIN exam_subject c ON b.sbj_cd = c.sbj_cd
AND a.EXAM_NM LIKE '%' #{searchKeyword} '%'
LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

mapper.insert:
INSERT INTO exam_pass_mst (
	EXAM_NM, SBJ_CD, ITEM_NO, PASS_ANS
) VALUES (
	#{examNm}, #{isUse}, #{itemNo}, #{passAns}
)
